#!/usr/bin/env node
/**
 * Extract a single version's section from ``CHANGELOG.md``.
 *
 * Used by the release pipeline to turn the bundled changelog into the
 * body of the GitHub Release, so the release notes mirror what users
 * see in the in-app **Help > Release notes** dialog instead of the
 * bare "Full Changelog" autogenerated text.
 *
 * Usage:
 *   node scripts/extract-changelog.mjs <version> [-o <file>]
 *
 * <version> may be given with or without a leading ``v`` (``0.3.0`` or
 * ``v0.3.0``). The extracted block is the content located between the
 * ``## [X.Y.Z] - YYYY-MM-DD`` heading and the next ``## [`` heading,
 * with the heading line removed and the ``### Added in X.Y.Z`` style
 * sub-headings normalised to ``### Added``.
 *
 * On success the section is written to the file given via ``-o`` (or to
 * stdout otherwise). If the version is not found, the script exits with
 * a non-zero status so the release job fails loudly rather than shipping
 * empty notes.
 */

import { readFileSync, writeFileSync } from "node:fs";
import { dirname, resolve } from "node:path";
import { fileURLToPath, pathToFileURL } from "node:url";

const ROOT = resolve(dirname(fileURLToPath(import.meta.url)), "..");
const CHANGELOG = resolve(ROOT, "CHANGELOG.md");

function fail(msg) {
  console.error(`\n❌ ${msg}\n`);
  process.exit(1);
}

/**
 * Extract the changelog body for ``version`` from the ``md`` text.
 *
 * Returns the normalised section (heading line removed, ``### XXX in
 * X.Y.Z`` sub-headings reduced to ``### XXX``). Returns ``null`` when no
 * matching version section exists.
 */
export function extractSection(md, version) {
  // Match ``## [X.Y.Z]`` exactly (optionally followed by `` - DATE``),
  // tolerating surrounding whitespace.
  const escaped = version.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  const headingRe = new RegExp(`^## \\[${escaped}\\][^\\n]*$`, "m");
  const m = md.match(headingRe);
  if (m == null || m.index === undefined) {
    return null;
  }
  const start = m.index + m[0].length;
  const nextIdx = md.indexOf("\n## [", start);
  const end = nextIdx === -1 ? md.length : nextIdx;
  let body = md.slice(start, end).trim();
  // For the oldest section there is no following ``## [`` heading, so the
  // bottom-of-file link-reference definitions (``[X.Y.Z]: <url>``) would be
  // captured. Drop any trailing block of such definitions.
  body = body.replace(/(?:^\[[^\]]+\]:\s+\S.*$\n?)+\s*$/m, "").trimEnd();
  // Normalise ``### Added in 0.3.0`` -> ``### Added``.
  const normalised = body.replace(
    /^(#{1,6}\s+.*?)\s+in\s+\d+\.\d+\.\d+\b.*$/gm,
    "$1",
  );
  return normalised;
}

function main() {
  const argv = process.argv.slice(2);
  let outFile = null;
  let version = null;
  for (let i = 0; i < argv.length; i += 1) {
    const arg = argv[i];
    if (arg === "-o" || arg === "--output") {
      outFile = argv[i + 1];
      i += 1;
    } else if (version === null) {
      version = arg;
    }
  }

  if (!version) {
    fail("Usage: node scripts/extract-changelog.mjs <version> [-o <file>]");
  }

  // Tolerate a leading ``v`` (e.g. from a git tag name).
  version = version.replace(/^v/, "");

  let md;
  try {
    md = readFileSync(CHANGELOG, "utf8");
  } catch {
    fail(`CHANGELOG.md not found at ${CHANGELOG}`);
  }

  const section = extractSection(md, version);
  if (section == null) {
    fail(
      `CHANGELOG.md: no section found for version ${version}.\n` +
        "Make sure the tag matches a promoted ``## [X.Y.Z]`` heading\n" +
        "(the release script promotes [Unreleased] at tag time).",
    );
  }

  if (outFile) {
    writeFileSync(resolve(ROOT, outFile), `${section}\n`);
  } else {
    process.stdout.write(`${section}\n`);
  }
}

// Only run the CLI when invoked directly (node scripts/extract-changelog.mjs),
// not when imported (unit tests, scripts/release.mjs).
if (import.meta.url === pathToFileURL(process.argv[1] ?? "").href) {
  main();
}
